DELETE FROM faq_items;

INSERT INTO faq_items (question, answer, sort_order, is_published)
VALUES 
('Как работает сервис CoolLike?', 'Мы предоставляем инструменты для повышения показателей в соцсетях. Вы вставляете ссылку, выбираете услугу, и наша система автоматически запускает процесс продвижения через сеть проверенных провайдеров.', 0, true),

('Безопасно ли это для моего профиля?', 'Да, мы используем собственные алгоритмы безопасной доставки, которые имитируют поведение реальных пользователей. Мы рекомендуем не превышать разумные лимиты и использовать плавную накрутку для новых аккаунтов.', 1, true),

('Почему мой профиль должен быть открытым?', 'Наши системы и системы провайдеров не могут получить доступ к закрытым (приватным) аккаунтам. Обязательно откройте профиль и проверьте доступность контента перед оформлением заказа.', 2, true),

('Что такое «Рефил» (Гарантия)?', 'Рефил — это бесплатное восстановление подписчиков или лайков в случае списаний со стороны социальной сети. Если в течение гарантийного срока показатели упали, система восстановит их бесплатно.', 3, true),

('Почему происходят списания (Дропы)?', 'Списания — это естественный процесс чистки социальных сетей от ботов и неактивных профилей. Для минимизации этого эффекта мы рекомендуем выбирать услуги с длительной гарантией (рефилом).', 4, true),

('Нужно ли мне давать пароль от аккаунта?', 'НЕТ. Мы никогда не запрашиваем пароли от ваших аккаунтов. Для работы нам нужна только публичная ссылка на ваш профиль или конкретную публикацию.', 5, true),

('Как быстро начнется выполнение заказа?', 'Старт большинства услуг происходит автоматически в течение 5-30 минут после оплаты. В редких случаях (при высокой нагрузке или технических работах соцсети) старт может занять до 2-4 часов.', 6, true),

('Что делать, если заказ не запустился через час?', 'Если статус заказа не изменился в течение часа, пожалуйста, напишите в нашу службу поддержки в Telegram. Мы проверим технические параметры и поможем ускорить процесс.', 7, true),

('Как правильно копировать ссылку на пост в Telegram?', 'Для каналов: нажмите на время публикации поста или на кнопку «Поделиться», затем выберите «Копировать ссылку». Для закрытых групп используйте специальные пригласительные ссылки.', 8, true),

('Особенности накрутки подписчиков в YouTube?', 'Для успешного старта на вашем канале должно быть загружено минимум 3 видео, а самому старому видео должно быть не менее 2 суток. Это помогает избежать фильтрации платформой.', 9, true),

('Можно ли отменить заказ?', 'Если выполнение заказа уже началось, отмена технически невозможна. Если заказ находится в статусе «В очереди», вы можете обратиться в поддержку для его отмены и возврата средств.', 10, true),

('Как повысить шансы на попадание в рекомендации?', 'Алгоритмы любят комплексность. Мы советуем заказывать одновременно подписчиков, лайки, сохранения и комментарии в пропорции 10:1 (на 1000 подписчиков — 100 лайков).', 11, true),

('Зачем нужна регистрация на сайте?', 'Регистрация происходит автоматически при первом заказе. Это позволяет нам хранить историю вашей активности, предоставлять скидки постоянным клиентам и отправлять фискальные чеки.', 12, true),

('Что будет, если я сменю никнейм во время заказа?', 'Ссылка станет недействительной, и поставка услуг прекратится. Мы настоятельно рекомендуем не менять никнейм (URL) аккаунта до завершения всех активных заказов.', 13, true),

('Где я могу увидеть чек об оплате?', 'Все финансовые документы и чеки доступны в вашем Личном кабинете в разделе «История транзакций» сразу после успешного проведения платежа.', 14, true);
